			default:
	+ 			/*
	+ 			 * to treat following function.
	+ 			 * func      (arg) {
	+ 			 * ....
	+ 			 * }
	+ 			 */
	+ 			if (c == ' ' || c == '\t') {
	+ 				int save = c;
	+ 				while (GETC(!=, EOF) && (c == ' ' || c == '\t'))
	+ 					;
	+ 				if (c == EOF)
	+ 					return;
	+ 				(void)ungetc(c, inf);
	+ 				c = save;
	+ 			}
		storec:		if (!intoken(c)) {
					if (sp == tok)
						break;
	***************
