	+ 	(void)ungetc(c, inf);

		curline = lineno;
		for (sp = tok;;) {		/* get next token */
How-To-Repeat: 
	test.c
	------------------------------------------
	# define macro()        printf("Hello")
	func   ()
	{
		print("Hello");
	}
	------------------------------------------

	% ctags -x test.c
	%

	It should be like this.

	func               2 test.c           func   ()
	macro              1 test.c           # define macro()  printf("Hello")
